$errors = array();
$success = array();

// 加欄位
$newCols = array(
    'offset_type' => "VARCHAR(20) DEFAULT '' COMMENT '立沖屬性'",
    'tx_type' => "VARCHAR(20) DEFAULT '' COMMENT '交易科目/統馭科目'",
    'type_num' => "VARCHAR(5) DEFAULT '' COMMENT '科目總類代碼'",
    'type_name_full' => "VARCHAR(50) DEFAULT '' COMMENT '總類名稱'",
    'cat_code' => "VARCHAR(10) DEFAULT '' COMMENT '科目類別代碼'",
    'cat_name' => "VARCHAR(50) DEFAULT '' COMMENT '類別名稱'",
    'attr' => "VARCHAR(30) DEFAULT '' COMMENT '科目屬性'",
    'project_calc' => "VARCHAR(30) DEFAULT '' COMMENT '專案核算'",
    'dept_calc' => "VARCHAR(30) DEFAULT '' COMMENT '部門核算'",
    'relate_type' => "VARCHAR(20) DEFAULT '' COMMENT '往來類型'",
    'internal_flag' => "VARCHAR(10) DEFAULT '' COMMENT '內部往來'",
);
foreach ($newCols as $col => $def) {
    try {
        $db->exec("ALTER TABLE chart_of_accounts ADD COLUMN {$col} {$def}");
        $success[] = "{$col} 欄位已新增";
    } catch (PDOException $e) {
        if (strpos($e->getMessage(), 'Duplicate column') !== false) {
            // already exists
        } else {
            $errors[] = "{$col}: " . $e->getMessage();
        }
    }
}

// 清除 + 重新匯入
