$updated = 0;
foreach ($accounts as $a) {
    if (!empty($a[3])) {
        try {
            $db->prepare("UPDATE chart_of_accounts SET parent_id = (SELECT id FROM (SELECT id FROM chart_of_accounts WHERE account_code = ?) AS tmp) WHERE account_code = ?")->execute(array($a[3], $a[0]));
            $updated++;
        } catch (PDOException $e) {}
    }
}
$success[] = "已更新 " . $updated . " 筆 parent_id";

